UPDATE NOTICE
SET    NTC_CNT = NTC_CNT + 1
WHERE  NTC_NO = #{ntcNo}

UPDATE NOTICE
SET    NTC_TTL = #{ntcTtl},
       NTC_CN = #{ntcCn},
       NTC_STTS = #{ntcStts}

       , FILE_ID = #{fileId}

WHERE  NTC_NO = #{ntcNo}

UPDATE FILE_DETAIL
SET    FILE_ID = #{newFileId}
WHERE  FILE_ID = #{oldFileId}
